//! Generated typed CubeSpace ADCS telemetry responses.

use crate::{codec, AdcsError, AdcsResult, DataType, FieldSpec, Telemetry, TelemetrySpec};
use async_graphql::SimpleObject;

fn ensure_len(payload: &[u8], expected: usize) -> AdcsResult<()> {
    if payload.len() < expected {
        Err(AdcsError::InvalidPayloadLength {
            expected,
            actual: payload.len(),
        })
    } else {
        Ok(())
    }
}

fn unknown_enum_label<T>(_value: T) -> Option<String> {
    None
}

