        let raw_rwl0_speed_command = codec::read_f32(payload, 304, 32, "RWL0 speed command")?;
        let raw_rwl1_speed_command = codec::read_f32(payload, 336, 32, "RWL1 speed command")?;
        let raw_rwl2_speed_command = codec::read_f32(payload, 368, 32, "RWL2 speed command")?;
        let raw_rwl3_speed_command = codec::read_f32(payload, 400, 32, "RWL3 speed command")?;
        let raw_rwl0_momentum_command = codec::read_f32(payload, 432, 32, "RWL0 momentum command")?;
        let raw_rwl1_momentum_command = codec::read_f32(payload, 464, 32, "RWL1 momentum command")?;
        let raw_rwl2_momentum_command = codec::read_f32(payload, 496, 32, "RWL2 momentum command")?;
        let raw_rwl3_momentum_command = codec::read_f32(payload, 528, 32, "RWL3 momentum command")?;
        let raw_rwl0_torque_command = codec::read_f32(payload, 560, 32, "RWL0 torque command")?;
