        let raw_rwl2_torque_command = codec::read_f32(payload, 624, 32, "RWL2 torque command")?;
        let raw_rwl3_torque_command = codec::read_f32(payload, 656, 32, "RWL3 torque command")?;
        let raw_mtq0_dipole_moment_command =
            codec::read_signed(payload, 688, 16, "MTQ0 dipole moment command")? as i16;
        let raw_mtq1_dipole_moment_command =
            codec::read_signed(payload, 704, 16, "MTQ1 dipole moment command")? as i16;
        let raw_mtq2_dipole_moment_command =
            codec::read_signed(payload, 720, 16, "MTQ2 dipole moment command")? as i16;
        let raw_mtq0_torque_command = codec::read_f32(payload, 736, 32, "MTQ0 torque command")?;
        let raw_mtq1_torque_command = codec::read_f32(payload, 768, 32, "MTQ1 torque command")?;
        let raw_mtq2_torque_command = codec::read_f32(payload, 800, 32, "MTQ2 torque command")?;
        let raw_mtq0_on_time_command =
            codec::read_signed(payload, 832, 16, "MTQ0 on-time command")? as i16;
        let raw_mtq1_on_time_command =
            codec::read_signed(payload, 848, 16, "MTQ1 on-time command")? as i16;
        let raw_mtq2_on_time_command =
            codec::read_signed(payload, 864, 16, "MTQ2 on-time command")? as i16;
        let raw_control_timeout = codec::read_unsigned(payload, 880, 16, "Control timeout")? as u16;
        let raw_active_control_mode =
            codec::read_unsigned(payload, 896, 8, "Active control mode")? as u8;
        let raw_rwl0_error_flag = codec::read_unsigned(payload, 904, 1, "RWL0 error flag")? != 0;
        let raw_rwl1_error_flag = codec::read_unsigned(payload, 905, 1, "RWL1 error flag")? != 0;
