        let raw_use_css_in_ekf = codec::read_unsigned(payload, 305, 1, "Use CSS in EKF")? != 0;
        let raw_use_hss_in_ekf = codec::read_unsigned(payload, 306, 1, "Use HSS in EKF")? != 0;
