impl Telemetry for BootStatusTelemetry {
    const ID: u8 = 137;
    const NAME: &'static str = "Boot Status";
    const LENGTH_BYTES: usize = 3;

    fn decode(payload: &[u8]) -> AdcsResult<Self> {
        ensure_len(payload, Self::LENGTH_BYTES)?;
        let raw_state = codec::read_unsigned(payload, 0, 8, "State")? as u8;
        let raw_reset_reason = codec::read_unsigned(payload, 8, 8, "Reset Reason")? as u8;
        let raw_shared_params_error =
            codec::read_unsigned(payload, 16, 1, "Shared Params Error")? != 0;
        let raw_port_validation_error =
            codec::read_unsigned(payload, 17, 1, "Port Validation Error")? != 0;
        let raw_port_discovery_error =
            codec::read_unsigned(payload, 18, 1, "Port Discovery Error")? != 0;
        let raw_otp_serial_number_error =
            codec::read_unsigned(payload, 19, 1, "OTP Serial Number Error")? != 0;
        let raw_config_serial_number_error =
            codec::read_unsigned(payload, 20, 1, "Config Serial Number Error")? != 0;
        let raw_serial_number_mismatch_error =
            codec::read_unsigned(payload, 21, 1, "Serial Number Mismatch Error")? != 0;
        let raw_config_invalid_error =
            codec::read_unsigned(payload, 22, 1, "Config invalid error")? != 0;
        Ok(Self {
            state_raw: raw_state,
            state: unknown_enum_label(raw_state),
            reset_reason_raw: raw_reset_reason,
            reset_reason: unknown_enum_label(raw_reset_reason),
            shared_params_error: raw_shared_params_error,
            port_validation_error: raw_port_validation_error,
            port_discovery_error: raw_port_discovery_error,
            otp_serial_number_error: raw_otp_serial_number_error,
            config_serial_number_error: raw_config_serial_number_error,
            serial_number_mismatch_error: raw_serial_number_mismatch_error,
            config_invalid_error: raw_config_invalid_error,
        })
    }
}

